import React, { useState } from 'react';
import API from '../api/axios';
import { useNavigate } from 'react-router-dom';

const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleLogin = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            const { data } = await API.post('/auth/login', { email, password });
            localStorage.setItem('token', data.token);
            localStorage.setItem('role', data.role);
            navigate('/dashboard');
        } catch (err) {
            alert(err.response?.data?.message || "Invalid email or password");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="login-page">
            {/* Embedded Professional CSS for Animations */}
            <style>{`
                .login-page {
                    height: 100vh;
                    display: flex;
                    justifyContent: center;
                    alignItems: center;
                    background: #0f172a;
                    overflow: hidden;
                    position: relative;
                    font-family: 'Inter', sans-serif;
                }

                /* Animated Background Circles */
                .area {
                    position: absolute;
                    top: 0; left: 0;
                    width: 100%; height: 100%;
                    z-index: 1;
                }
                .circles {
                    position: absolute;
                    top: 0; left: 0;
                    width: 100%; height: 100%;
                    overflow: hidden;
                    margin: 0; padding: 0;
                }
                .circles li {
                    position: absolute;
                    display: block;
                    list-style: none;
                    width: 20px; height: 20px;
                    background: rgba(255, 255, 255, 0.1);
                    animation: animate 25s linear infinite;
                    bottom: -150px;
                    border-radius: 4px;
                }
                @keyframes animate {
                    0%{ transform: translateY(0) rotate(0deg); opacity: 1; border-radius: 0; }
                    100%{ transform: translateY(-1000px) rotate(720deg); opacity: 0; border-radius: 50%; }
                }
                .circles li:nth-child(1){ left: 25%; width: 80px; height: 80px; animation-delay: 0s; }
                .circles li:nth-child(2){ left: 10%; width: 20px; height: 20px; animation-delay: 2s; animation-duration: 12s; }
                .circles li:nth-child(3){ left: 70%; width: 20px; height: 20px; animation-delay: 4s; }
                .circles li:nth-child(4){ left: 40%; width: 60px; height: 60px; animation-delay: 0s; animation-duration: 18s; }

                /* Glassmorphism Card */
                .login-card {
                    z-index: 2;
                    background: rgba(255, 255, 255, 0.05);
                    backdrop-filter: blur(15px);
                    border: 1px solid rgba(255, 255, 255, 0.1);
                    padding: 45px;
                    border-radius: 20px;
                    width: 100%;
                    max-width: 420px;
                    box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
                    text-align: center;
                }

                .login-card h1 { color: #fff; font-size: 2.5rem; margin-bottom: 10px; letter-spacing: -1px; }
                .login-card p { color: #94a3b8; margin-bottom: 30px; font-size: 0.95rem; }

                .input-group { margin-bottom: 20px; text-align: left; }
                .input-group label { display: block; color: #cbd5e1; margin-bottom: 8px; font-size: 0.85rem; }
                .input-group input {
                    width: 100%;
                    padding: 14px;
                    background: rgba(15, 23, 42, 0.6);
                    border: 1px solid #334155;
                    border-radius: 10px;
                    color: #fff;
                    font-size: 1rem;
                    transition: 0.3s;
                    box-sizing: border-box;
                }
                .input-group input:focus { outline: none; border-color: #38bdf8; box-shadow: 0 0 0 2px rgba(56, 189, 248, 0.2); }

                .login-btn {
                    width: 100%;
                    padding: 14px;
                    background: linear-gradient(to right, #38bdf8, #818cf8);
                    border: none;
                    border-radius: 10px;
                    color: white;
                    font-size: 1rem;
                    font-weight: 600;
                    cursor: pointer;
                    transition: 0.3s;
                    margin-top: 10px;
                }
                .login-btn:hover { transform: translateY(-2px); box-shadow: 0 10px 20px -5px rgba(56, 189, 248, 0.5); }
                .login-btn:disabled { opacity: 0.6; cursor: not-allowed; }
            `}</style>

            {/* Background Animation Elements */}
            <div className="area">
                <ul className="circles">
                    <li></li><li></li><li></li><li></li><li></li><li></li><li></li>
                </ul>
            </div>

            {/* Login Content */}
            <div className="login-card">
                <h1>TMS</h1>
                <p>Ticket Management System</p>

                <form onSubmit={handleLogin}>
                    <div className="input-group">
                        <label>Support Email</label>
                        <input 
                            type="email" 
                            placeholder="name@company.com" 
                            onChange={e => setEmail(e.target.value)} 
                            required 
                        />
                    </div>
                    <div className="input-group">
                        <label>Secure Password</label>
                        <input 
                            type="password" 
                            placeholder="••••••••" 
                            onChange={e => setPassword(e.target.value)} 
                            required 
                        />
                    </div>
                    <button type="submit" className="login-btn" disabled={loading}>
                        {loading ? 'Validating Access...' : 'Sign In to Portal'}
                    </button>
                </form>

                <div style={{ marginTop: '30px', color: '#64748b', fontSize: '0.75rem' }}>
                    SECURE ENCRYPTED ACCESS ONLY
                </div>
            </div>
        </div>
    );
};

export default Login;
